    auto_exchange_rate?: boolean
    /**
     * If true, this will mark a transaction as billable. Supported for Sage Intacct v2 and Zoho Books.
     */
    billable?: boolean
    /**
     * If true, this will mark a transaction as reconciled. Supported for Xero.
     */
