  /**
   * The Rutter generated unique ID of the tax rate.
   */
  id: string
  /**
   * The platform specific ID of the tax rate.
   */
  platform_id: string
  /**
   * The status of the tax rate.
   */
  status: 'active' | 'inactive' | 'unknown'
  /**
   * The tax code of the tax rate.
   */
  code: string | null
  /**
   * Where there are multiple components of a tax, each component may be calculated on the original amount and added together. Alternatively, one tax may be calculated on the sub-total of the original amount plus another tax, which is referred to as compounding. When there is compounding, the effective tax rate is the rate that, if applied to the original amount, would result in the total amount of tax with compounding.
   */
  effective_tax_rate: number | null
  /**
   * The name of the tax rate.
   */
  name: string | null
  /**
   * The total tax rate. This is the sum of the components of a tax rate, not including compounding.
   */
  total_tax_rate: number | null
  /**
   * An array of [Subsidiaries](/rest/version/subsidiaries) linked to the tax rate. Supported for NetSuite and Sage Intacct.
   */
  subsidiaries: Array<{
    id: string
  }>
  /**
   * Tax rates can break into multiple sub taxes that are then combined in various ways. These sub taxes are called components. Supported for Dynamics 365 Business Central, NetSuite, QuickBooks, QuickBooks Desktop, and Xero.
   */
  components: Array<{
    /**
     * Whether this component should compound the total or not. For Dynamics 365 Business Central, this field will always return false as the platform does not specify tax types programmatically.
     */
    is_compound: boolean
    /**
     * Whether this component is assosciated with purchases tax. For Dynamics 365 Business Central, this field will always return false as the platform does not specify tax types programmatically.
     */
    is_purchases_tax: boolean
    /**
     * Whether this component is assosciated with sales tax. For Dynamics 365 Business Central, this field will always return false as the platform does not specify tax types programmatically.
     */
    is_sales_tax: boolean
    /**
     * Name of the sub tax this component represents.
     */
    name: string
    /**
     * Tax rate of the component or sub tax.
     */
    rate: number
  }>
  /**
   * Additional fields required only for a narrow set of use cases.
   */
  additional_fields?: {
    /**
     * The total tax rate for purchases taxes only. This is the sum of the components of a tax rate, not including compounding.
     */
    purchase_total_tax_rate: number | null
    /**
     * The total tax rate for sales taxes only. This is the sum of the components of a tax rate, not including compounding.
     */
    sales_total_tax_rate: number | null
  }
  /**
   * The [ISO 8601](https://www.iso.org/iso-8601-date-and-time-format.html) timestamp that the tax rate object was created.
   */
  created_at: string | null
  /**
   * The [ISO 8601](https://www.iso.org/iso-8601-date-and-time-format.html) timestamp that the tax rate object was last updated.
   */
  updated_at: string | null
  /**
   * The [ISO 8601](https://www.iso.org/iso-8601-date-and-time-format.html) timestamp when the tax rates was last synced by Rutter.
   */
